import {
  forwardRef,
  type CSSProperties,
  type ElementType,
  type ReactNode,
} from 'react';
import { cn, vc } from '../../utils/cn';
import styles from './Stack.module.css';

export type StackDirection = 'horizontal' | 'vertical';
export type StackAlign = 'start' | 'center' | 'end' | 'stretch';
export type StackJustify = 'start' | 'center' | 'end' | 'between' | 'around';

export interface StackProps {
  direction?: StackDirection;
  /** Spacing token (1–12) or any CSS length. */
  gap?: string | number;
  align?: StackAlign;
  justify?: StackJustify;
  wrap?: boolean;
  as?: ElementType;
  className?: string;
  style?: CSSProperties;
  children?: ReactNode;
  'data-testid'?: string;
}

export const Stack = forwardRef<HTMLElement, StackProps>(function Stack(
  {
    direction = 'vertical',
    gap = '4',
    align,
    justify,
    wrap = false,
    as,
    className,
    style,
    children,
    'data-testid': dataTestId = 'tatva-stack',
  },
  ref,
) {
  const Component = (as ?? 'div') as ElementType;
  const gapVal =
    typeof gap === 'number' || /^\d+$/.test(String(gap))
      ? `var(--tatva-space-${gap})`
      : gap;
  return (
    <Component
      ref={ref}
      className={cn(
        styles.stack,
        vc(styles, 'direction', direction),
        align && vc(styles, 'align', align),
        justify && vc(styles, 'justify', justify),
        wrap && styles.wrap,
        className,
      )}
      style={{ gap: gapVal, ...style }}
      data-testid={dataTestId}
    >
      {children}
    </Component>
  );
});

.stack {
  display: flex;
}

.directionVertical {
  flex-direction: column;
}
.directionHorizontal {
  flex-direction: row;
}

.alignStart {
  align-items: flex-start;
}
.alignCenter {
  align-items: center;
}
.alignEnd {
  align-items: flex-end;
}
.alignStretch {
  align-items: stretch;
}

.justifyStart {
  justify-content: flex-start;
}
.justifyCenter {
  justify-content: center;
}
.justifyEnd {
  justify-content: flex-end;
}
.justifyBetween {
  justify-content: space-between;
}
.justifyAround {
  justify-content: space-around;
}

.wrap {
  flex-wrap: wrap;
}

export { Stack } from './Stack';
export type {
  StackProps,
  StackDirection,
  StackAlign,
  StackJustify,
} from './Stack';
